1	//! Graph data model for the tamarin web-UI constraint-system graph.
2	//!
3	//! This is an independent model designed from the observed DOT payloads
4	//! (see workspace/BEHAVIOR.md). A [`Graph`] is an ordered list of top-level
5	//! [`Stmt`]s rendered under one of two header styles. The [`crate::dot`]
6	//! serializer turns a `Graph` back into byte-exact DOT text.
7	
8	/// Which top-level attribute header to emit.
9	///
10	/// Per the observed trigger rule (BEHAVIOR.md §4), [`Header::Compact`] is used
11	/// exactly when the graph carries a node with a non-`Undefined` role; otherwise
12	/// [`Header::Simple`]. [`Graph::infer_header`] applies that rule.
13	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
14	pub enum Header {
15	    /// Plain multiset-rewriting graph header (`nodesep="0.3"`, …).
16	    Simple,
17	    /// Clustered/process graph header (`packmode="cluster"`, `compound="true"`, …).
18	    Compact,
19	}
20	
21	/// The role annotation carried by a record node.
22	///
23	/// `Undefined` is the sentinel for plain multiset-rewriting rules; any other
24	/// value denotes a process/agent role and triggers clustering.
25	#[derive(Clone, Debug, PartialEq, Eq)]
26	pub struct Role(pub String);
27	
28	impl Role {
29	    pub const UNDEFINED: &'static str = "Undefined";
30	    pub fn undefined() -> Self {
31	        Role(Self::UNDEFINED.to_string())
32	    }
33	    pub fn is_undefined(&self) -> bool {
34	        self.0 == Self::UNDEFINED
35	    }
36	}
37	
38	/// A whole graph: the two node/edge default lines are chosen by `header`, and
39	/// `body` holds every statement in emission order.
40	#[derive(Clone, Debug)]
41	pub struct Graph {
42	    pub header: Header,
43	    pub body: Vec<Stmt>,
44	}
45	
46	impl Graph {
47	    pub fn new(header: Header) -> Self {
48	        Graph { header, body: Vec::new() }
49	    }
50	
51	    pub fn push(&mut self, s: Stmt) -> &mut Self {
52	        self.body.push(s);
53	        self
54	    }
55	
56	    /// Apply the observed clustering trigger (BEHAVIOR.md §4): compact iff any
57	    /// record node anywhere in the graph has a non-`Undefined` role.
58	    pub fn infer_header(&self) -> Header {
59	        if self.body.iter().any(stmt_has_role_node) {
60	            Header::Compact
61	        } else {
62	            Header::Simple
63	        }
64	    }
65	
66	    /// Set `header` to the inferred value.
67	    pub fn set_inferred_header(&mut self) {
68	        self.header = self.infer_header();
69	    }
70	}
71	
72	fn stmt_has_role_node(s: &Stmt) -> bool {
73	    match s {
74	        Stmt::Node(n) => n.has_defined_role(),
75	        Stmt::Cluster(c) => c.body.iter().any(stmt_has_role_node),
76	        Stmt::RankBlock(b) => b.body.iter().any(stmt_has_role_node),
77	        Stmt::Edge(_) => false,
78	    }
79	}
80	
81	/// A top-level (or nested) statement, emitted in list order.
82	#[derive(Clone, Debug)]
83	pub enum Stmt {
84	    Node(Node),
85	    Edge(Edge),
86	    /// A `subgraph "cluster_…" { … }` block (compact/clustered mode).
87	    Cluster(Cluster),
88	    /// An anonymous `{ rank="sink"; … }` block (used for the legend).
89	    RankBlock(RankBlock),
90	}
91	
92	/// A DOT node statement. `id` is the full graphviz identifier verbatim, e.g.
93	/// `"n5"`. Ports ([`Cell::port`]) and edge endpoints ([`EndPoint`]) use the same
94	/// full-string convention (`"n2"`), so the serializer emits ids as given.
95	#[derive(Clone, Debug)]
96	pub struct Node {
97	    pub id: String,
98	    pub kind: NodeKind,
99	}
100	
101	impl Node {
102	    pub fn record(id: impl Into<String>, r: Record) -> Self {
103	        Node { id: id.into(), kind: NodeKind::Record(r) }
104	    }
105	    pub fn ellipse(id: impl Into<String>, e: Ellipse) -> Self {
106	        Node { id: id.into(), kind: NodeKind::Ellipse(e) }
107	    }
108	    pub fn plain(id: impl Into<String>, html: impl Into<String>) -> Self {
109	        Node { id: id.into(), kind: NodeKind::Plain { html: html.into() } }
110	    }
111	    /// A node with an arbitrary `shape` (e.g. `invtrapezium`).
112	    pub fn shaped(id: impl Into<String>, s: Shaped) -> Self {
113	        Node { id: id.into(), kind: NodeKind::Shaped(s) }
114	    }
115	    pub fn has_defined_role(&self) -> bool {
116	        matches!(&self.kind, NodeKind::Record(r) if !r.role.is_undefined())
117	    }
118	}
119	
120	#[derive(Clone, Debug)]
121	pub enum NodeKind {
122	    /// Rule / graph-node instance drawn as a graphviz record.
123	    Record(Record),
124	    /// Atomic knowledge / action / temporal node drawn as an ellipse.
125	    Ellipse(Ellipse),
126	    /// A node with an explicit `shape` other than `record`/`ellipse`/`plain`.
127	    ///
128	    /// Observed live (never in the crawled proof-graph corpus, which is all
129	    /// solved states): a `(#var, idx)` placeholder for an *unresolved graph node*
130	    /// referenced by a still-open premise is drawn `shape="invtrapezium"` — e.g.
131	    /// `n9[label="(#i, 0)",shape="invtrapezium"]`, fed by the conclusion that must
132	    /// satisfy premise `idx` of the missing node `#var`. Serialization matches an
133	    /// [`Ellipse`] exactly (`label,shape[,color]`); only the `shape` string
134	    /// differs, so this variant also carries the observed `"invtrapezium"`.
135	    /// `"trapezium"` is named by the spec as the dual but was **not observed** in
136	    /// the corpus or any live probe (see BEHAVIOR.md §3d); the serializer supports
137	    /// any shape string so it can be emitted if a caller supplies one.
138	    Shaped(Shaped),
139	    /// The abbreviation legend, an HTML-like label. `html` is the inner content
140	    /// between `label=<` and `>` (i.e. it starts with `<TABLE …`).
141	    Plain { html: String },
142	}
143	
144	/// A record node's label and styling. `columns` are the top-level record groups
145	/// (`{…}|{…}|{…}`, typically premises / rule-info / conclusions); each column is
146	/// a list of ported cells joined by `|`.
147	#[derive(Clone, Debug)]
148	pub struct Record {
149	    pub columns: Vec<Vec<Cell>>,
150	    pub fillcolor: String,
151	    pub fontcolor: String,
152	    pub role: Role,
153	}
154	
155	/// One ported record cell: `<n{port}> {text}`. `text` is taken pre-rendered
156	/// (already escaped/wrapped); see BEHAVIOR.md §3a on why wrapping is a gap.
157	#[derive(Clone, Debug)]
158	pub struct Cell {
159	    pub port: String,
160	    pub text: String,
161	}
162	
163	impl Cell {
164	    pub fn new(port: impl Into<String>, text: impl Into<String>) -> Self {
165	        Cell { port: port.into(), text: text.into() }
166	    }
167	}
168	
169	#[derive(Clone, Debug)]
170	pub struct Ellipse {
171	    pub label: String,
172	    pub color: Option<String>,
173	}
174	
175	impl Ellipse {
176	    pub fn new(label: impl Into<String>) -> Self {
177	        Ellipse { label: label.into(), color: None }
178	    }
179	    pub fn colored(label: impl Into<String>, color: impl Into<String>) -> Self {
180	        Ellipse { label: label.into(), color: Some(color.into()) }
181	    }
182	}
183	
184	/// A node carrying an explicit `shape` string (anything but record/ellipse/plain).
185	/// Serialized identically to an [`Ellipse`] — `label="…",shape="…"[,color="…"]` —
186	/// with `shape` supplied verbatim. Observed value: `invtrapezium` (BEHAVIOR.md §3d).
187	#[derive(Clone, Debug)]
188	pub struct Shaped {
189	    pub label: String,
190	    pub shape: String,
191	    pub color: Option<String>,
192	}
193	
194	impl Shaped {
195	    pub fn new(shape: impl Into<String>, label: impl Into<String>) -> Self {
196	        Shaped { label: label.into(), shape: shape.into(), color: None }
197	    }
198	    /// The observed `invtrapezium` placeholder for an unresolved node referenced
199	    /// by an open premise, labelled `(#var, idx)`. `node_var` is the temporal
200	    /// variable name without its `#` sigil (e.g. `"i"` ⇒ `(#i, 0)`).
201	    pub fn invtrapezium(node_var: &str, premise_index: usize) -> Self {
202	        Shaped::new("invtrapezium", format!("(#{}, {})", node_var, premise_index))
203	    }
204	}
205	
206	/// One endpoint of an edge: node id plus optional record port.
207	#[derive(Clone, Debug)]
208	pub struct EndPoint {
209	    pub node: String,
210	    pub port: Option<String>,
211	}
212	
213	impl EndPoint {
214	    pub fn node(node: impl Into<String>) -> Self {
215	        EndPoint { node: node.into(), port: None }
216	    }
217	    pub fn port(node: impl Into<String>, port: impl Into<String>) -> Self {
218	        EndPoint { node: node.into(), port: Some(port.into()) }
219	    }
220	}
221	
222	/// An edge statement. `attrs` are `(key, value)` pairs emitted in list order as
223	/// `[k="v",…]` (see BEHAVIOR.md §3c for the observed style vocabulary).
224	#[derive(Clone, Debug)]
225	pub struct Edge {
226	    pub src: EndPoint,
227	    pub dst: EndPoint,
228	    pub attrs: Vec<(String, String)>,
229	}
