1	//! Global `n<K>` node-id / port allocation (BEHAVIOR.md §3e).
2	//!
3	//! Observed rule, byte-consistent over **all 12 022** corpus graphs
4	//! (`mine_ids.py`, 12022/12022): the graph uses one monotonic counter starting
5	//! at 0, and identifiers are handed out in **emission order** so that id order ==
6	//! file order. For each node, in order:
7	//!   * a **record** first consumes one id per record *cell* (its `<port>`s), in
8	//!     cell order (premises, then the info cell, then conclusions), and then one
9	//!     more id for the node itself — so a record with `k` cells occupies ids
10	//!     `p, p+1, …, p+k-1` (ports) and `p+k` (node);
11	//!   * every other node kind (**ellipse**, **plain** legend, **invtrapezium**, …)
12	//!     consumes exactly one id, the node id.
13	//!
14	//! Example (`n7` from a real graph): 4 premise + 1 info + 3 conclusion cells take
15	//! ports `n0…n6`, then the node is `n7`; the next ellipse is `n8`. The scheme is
16	//! independent of the term contents; it depends only on the emission order and
17	//! each node's cell count.
18	
19	/// A single monotonic `n<K>` id source implementing the observed allocation.
20	#[derive(Debug, Default, Clone)]
21	pub struct NodeIdAllocator {
22	    next: usize,
23	}
24	
25	impl NodeIdAllocator {
26	    pub fn new() -> Self {
27	        Self { next: 0 }
28	    }
29	
30	    /// The next raw id value that would be handed out (for assertions/tests).
31	    pub fn peek(&self) -> usize {
32	        self.next
33	    }
34	
35	    /// Take one id, formatted `n<K>`.
36	    fn take(&mut self) -> String {
37	        let s = format!("n{}", self.next);
38	        self.next += 1;
39	        s
40	    }
41	
42	    /// Allocate ids for a **record** with `n_cells` cells: returns the `n_cells`
43	    /// port ids (in cell order) followed by the node id. Ports precede the node,
44	    /// matching the observed scheme.
45	    pub fn record(&mut self, n_cells: usize) -> RecordIds {
46	        let ports = (0..n_cells).map(|_| self.take()).collect();
47	        let node = self.take();
48	        RecordIds { ports, node }
49	    }
50	
51	    /// Allocate the single id of a non-record node (ellipse / plain / shaped).
52	    pub fn node(&mut self) -> String {
53	        self.take()
54	    }
55	}
56	
57	/// The ids a record occupies: one `port` per cell, then the `node` id.
58	#[derive(Debug, Clone)]
59	pub struct RecordIds {
60	    pub ports: Vec<String>,
61	    pub node: String,
62	}
63	
64	#[cfg(test)]
65	mod tests {
66	    use super::*;
67	
68	    #[test]
69	    fn record_takes_ports_then_node() {
70	        let mut a = NodeIdAllocator::new();
71	        // A record with 8 cells (4 prem + 1 info + 3 concl): ports n0..n7, node n8.
72	        let r = a.record(8);
73	        assert_eq!(r.ports, ["n0", "n1", "n2", "n3", "n4", "n5", "n6", "n7"]);
74	        assert_eq!(r.node, "n8");
75	        // next ellipse is n9.
76	        assert_eq!(a.node(), "n9");
77	    }
78	
79	    #[test]
80	    fn interleaved_matches_observed_sequence() {
81	        // Reproduce the id sequence of the real graph in BEHAVIOR.md §3e:
82	        // record(8)->n8, ellipse->n9, ellipse->n?, record(5)->n15, ...
83	        let mut a = NodeIdAllocator::new();
84	        assert_eq!(a.record(8).node, "n8");
85	        assert_eq!(a.node(), "n9"); // ellipse
86	        assert_eq!(a.node(), "n10"); // ellipse
87	        let r = a.record(5); // ports n11..n15? no: n11..n15 is 5 -> node n16
88	        assert_eq!(r.ports, ["n11", "n12", "n13", "n14", "n15"]);
89	        assert_eq!(r.node, "n16");
90	    }
91	}
