1	//! A minimal term model, sufficient to drive abbreviation (naming + expansion
2	//! rendering). It is an independent design; it renders tamarin-like surface
3	//! syntax for the common term shapes observed in legend expansions
4	//! (variables, constants, pairs, `exp`/`mult`/`union`/`xor`, function apps).
5	//!
6	//! Faithful reproduction of the solver's full term pretty-printer (all operators,
7	//! precedence, line wrapping) is out of scope — see BEHAVIOR.md §3a/§5. The
8	//! covered shapes are byte-tested against captured legend rows.
9	
10	use std::collections::HashMap;
11	
12	/// A term. Variable kinds mirror tamarin's surface decorations.
13	#[derive(Clone, Debug, PartialEq, Eq)]
14	pub enum Term {
15	    /// Fresh variable, rendered `~name`.
16	    Fresh(String),
17	    /// Public variable, rendered `$name`.
18	    Pub(String),
19	    /// Bare message/temporal variable, rendered `name`.
20	    Msg(String),
21	    /// Public constant, rendered `'name'`.
22	    Const(String),
23	    /// Right-nested pair; rendered flattened as `<a, b, c>`.
24	    Pair(Box<Term>, Box<Term>),
25	    /// `exp(base, e)`, rendered `base^e` (the exponent carries its own parens
26	    /// when it is a product/sum).
27	    Exp(Box<Term>, Box<Term>),
28	    /// An associative-commutative operator rendered infix inside parentheses:
29	    /// `mult`→`*`, `union`→`++`, `xor`→`⊕`. `func` is the logical name used for
30	    /// the abbreviation prefix.
31	    Ac { func: String, op: String, args: Vec<Term> },
32	    /// Ordinary prefix application `func(a, b, …)`.
33	    App { func: String, args: Vec<Term> },
34	}
35	
36	impl Term {
37	    // ---- convenience constructors --------------------------------------
38	
39	    pub fn fresh(n: &str) -> Term {
40	        Term::Fresh(n.to_string())
41	    }
42	    pub fn pubv(n: &str) -> Term {
43	        Term::Pub(n.to_string())
44	    }
45	    pub fn msg(n: &str) -> Term {
46	        Term::Msg(n.to_string())
47	    }
48	    pub fn cst(n: &str) -> Term {
49	        Term::Const(n.to_string())
50	    }
51	    pub fn app(func: &str, args: Vec<Term>) -> Term {
52	        Term::App { func: func.to_string(), args }
53	    }
54	    pub fn exp(base: Term, e: Term) -> Term {
55	        Term::Exp(Box::new(base), Box::new(e))
56	    }
57	    pub fn mult(args: Vec<Term>) -> Term {
58	        Term::Ac { func: "mult".into(), op: "*".into(), args }
59	    }
60	    pub fn union(args: Vec<Term>) -> Term {
61	        Term::Ac { func: "union".into(), op: "++".into(), args }
62	    }
63	    pub fn xor(args: Vec<Term>) -> Term {
64	        Term::Ac { func: "xor".into(), op: "\u{2295}".into(), args }
65	    }
66	    /// Build a flattened tuple `<a, b, c>` from ≥1 elements (right-nested pairs).
67	    pub fn tuple(mut elems: Vec<Term>) -> Term {
68	        let last = elems.pop().expect("tuple needs ≥1 element");
69	        elems.into_iter().rev().fold(last, |acc, e| Term::Pair(Box::new(e), Box::new(acc)))
70	    }
71	
72	    // ---- naming --------------------------------------------------------
73	
74	    /// The root symbol's *name*, whose first two letters give the abbreviation
75	    /// prefix (see [`crate::abbrev::prefix_for_symbol`]).
76	    pub fn root_symbol_name(&self) -> String {
77	        match self {
78	            Term::Fresh(n) | Term::Pub(n) | Term::Msg(n) | Term::Const(n) => n.clone(),
79	            Term::Pair(..) => "pair".to_string(),
80	            Term::Exp(..) => "exp".to_string(),
81	            Term::Ac { func, .. } => func.clone(),
82	            Term::App { func, .. } => func.clone(),
83	        }
84	    }
85	
86	    /// Leaf terms (variables/constants) are atomic; everything else is not.
87	    pub fn is_atomic(&self) -> bool {
88	        matches!(self, Term::Fresh(_) | Term::Pub(_) | Term::Msg(_) | Term::Const(_))
89	    }
90	
91	    /// A tuple / pair `<a, b, …>`. Tuples are never abbreviated (BEHAVIOR.md §5c,
92	    /// observed: 0 of 97 538 legend entries is a top-level tuple, and a live probe
93	    /// left a length-18 tuple occurring twice un-abbreviated).
94	    pub fn is_tuple(&self) -> bool {
95	        matches!(self, Term::Pair(..))
96	    }
97	
98	    /// Number of Unicode scalar values in the fully-expanded surface rendering —
99	    /// the measure that gates abbreviation (BEHAVIOR.md §5c). This counts the
100	    /// surface decorations too (`'…'` quotes, `~`/`$` sigils), matching the
101	    /// observed boundary (`'12345678'` = 10 chars is abbreviated, `'1234567'` = 9
102	    /// is not).
103	    pub fn render_len(&self) -> usize {
104	        self.render_full().chars().count()
105	    }
106	
107	    /// Number of term nodes (atoms + operators) — a simple complexity measure.
108	    pub fn size(&self) -> usize {
109	        match self {
110	            Term::Fresh(_) | Term::Pub(_) | Term::Msg(_) | Term::Const(_) => 1,
111	            Term::Pair(a, b) => 1 + a.size() + b.size(),
112	            Term::Exp(a, b) => 1 + a.size() + b.size(),
113	            Term::Ac { args, .. } | Term::App { args, .. } => {
114	                1 + args.iter().map(Term::size).sum::<usize>()
115	            }
116	        }
117	    }
118	
119	    /// Visit this term and every sub-term (pre-order).
120	    pub fn for_each_subterm(&self, f: &mut dyn FnMut(&Term)) {
121	        f(self);
122	        match self {
123	            Term::Pair(a, b) | Term::Exp(a, b) => {
124	                a.for_each_subterm(f);
125	                b.for_each_subterm(f);
126	            }
127	            Term::Ac { args, .. } | Term::App { args, .. } => {
128	                for a in args {
129	                    a.for_each_subterm(f);
130	                }
131	            }
132	            _ => {}
133	        }
134	    }
135	
136	    // ---- rendering -----------------------------------------------------
137	
138	    /// Fully-expanded surface rendering (no abbreviations). Used as the dedup key.
139	    pub fn render_full(&self) -> String {
140	        self.render_with(&|t| t.render_full())
141	    }
142	
143	    /// Render this term's expansion, replacing any *registered* sub-term (present
144	    /// in `table`, keyed by its full rendering) with its abbreviation name. The
145	    /// top-level term itself is always rendered structurally.
146	    pub fn render_abbrev(&self, table: &HashMap<String, String>) -> String {
147	        self.render_with(&|t| t.substitute(table))
148	    }
149	
150	    /// Rendering used for children during abbreviation: a registered term yields
151	    /// its name, otherwise it renders structurally (recursing on its children).
152	    fn substitute(&self, table: &HashMap<String, String>) -> String {
153	        if let Some(name) = table.get(&self.render_full()) {
154	            return name.clone();
155	        }
156	        self.render_with(&|t| t.substitute(table))
157	    }
158	
159	    /// Structural rendering; `child` renders each immediate sub-term.
160	    fn render_with(&self, child: &dyn Fn(&Term) -> String) -> String {
161	        match self {
162	            Term::Fresh(n) => format!("~{}", n),
163	            Term::Pub(n) => format!("${}", n),
164	            Term::Msg(n) => n.clone(),
165	            Term::Const(n) => format!("'{}'", n),
166	            Term::Pair(..) => {
167	                let elems = self.pair_spine();
168	                let parts: Vec<String> = elems.iter().map(|t| child(t)).collect();
169	                format!("<{}>", parts.join(", "))
170	            }
171	            Term::Exp(base, e) => format!("{}^{}", child(base), child(e)),
172	            Term::Ac { op, args, .. } => {
173	                let parts: Vec<String> = args.iter().map(|t| child(t)).collect();
174	                format!("({})", parts.join(op))
175	            }
176	            Term::App { func, args } => {
177	                let parts: Vec<String> = args.iter().map(|t| child(t)).collect();
178	                format!("{}({})", func, parts.join(", "))
179	            }
180	        }
181	    }
182	
183	    /// Flatten a right-nested pair into its element spine.
184	    fn pair_spine(&self) -> Vec<&Term> {
185	        let mut out = Vec::new();
186	        let mut cur = self;
187	        while let Term::Pair(a, b) = cur {
188	            out.push(a.as_ref());
189	            cur = b.as_ref();
190	        }
191	        out.push(cur);
192	        out
193	    }
194	}
195

1	//! Node abbreviation (BEHAVIOR.md §5): assigning short NAMES to complex terms
2	//! and rendering the legend table.
3	//!
4	//! Four things here are determined by observation and tested:
5	//!   * [`prefix_for_symbol`] — the `PREFIX` derivation,
6	//!   * [`Abbreviator`] — per-prefix sequential numbering + nesting substitution,
7	//!   * [`legend_html`] — the exact `<TABLE …>` bytes incl. the 65-space hang indent,
8	//!   * [`select`] — the SELECTION rule: abbreviate a sub-term iff its rendered
9	//!     length ≥ 10 and it occurs ≥ 2 times and it is not a tuple (§5c). Both
10	//!     necessary gates are corpus-exact (0 counterexamples / 97 538 abbreviations)
11	//!     and each was confirmed by a controlled black-box probe.
12	//!
13	//! The remaining gaps are the canonical numbering tie-break (§5b; the caller
14	//! controls insertion order) and, for DH/AC sub-terms, whose occurrences tamarin
15	//! counts over a normalised form (§5c residual).
16	
17	use std::collections::HashMap;
18	
19	use crate::term::Term;
20	
21	/// The opening tag of every legend table. Its byte length is the hang-indent
22	/// applied to continuation `<TR>` rows.
23	pub const TABLE_OPEN: &str =
24	    "<TABLE BORDER=\"1\" CELLBORDER=\"0\" CELLSPACING=\"3\" CELLPADDING=\"1\">";
25	
26	/// `PREFIX` for an abbreviation name: the first two *alphabetic* characters of
27	/// `name`, uppercased (one char if only one letter exists). Non-letters (digits,
28	/// `_`, `.`) are skipped. This is applied to the root symbol's *name* — for a
29	/// function `f(..)` that is `f`; for a constant `'c'` it is `c`; for a variable
30	/// `~v`/`$v`/`v` it is `v`; for an infix operator it is the operator's function
31	/// name (see [`Term::root_symbol_name`], which maps `^`→`exp`, `*`→`mult`,
32	/// `++`→`union`, `⊕`→`xor`).
33	///
34	/// Examples (all observed): `sign`→`SI`, `senc`→`SE`, `hash`→`HA`, `h2`→`H`,
35	/// `KDF`→`KD`, `pk`→`PK`, `aenc`→`AE`, `exp`→`EX`, `mult`→`MU`, `union`→`UN`,
36	/// `xor`→`XO`, `uninitialized`→`UN`, `F_status`→`FS`, `AMF_UE_NGAP_ID`→`AM`.
37	pub fn prefix_for_symbol(name: &str) -> String {
38	    name.chars()
39	        .filter(|c| c.is_ascii_alphabetic())
40	        .take(2)
41	        .flat_map(|c| c.to_uppercase())
42	        .collect()
43	}
44	
45	/// Assigns and remembers abbreviation names, de-duplicating identical terms and
46	/// numbering `1,2,3,…` per prefix in the order terms are [`Abbreviator::add`]ed.
47	///
48	/// Numbering order matches tamarin only where the canonical order is
49	/// unambiguous (see BEHAVIOR.md §5b); the caller decides insertion order.
50	#[derive(Default)]
51	pub struct Abbreviator {
52	    /// name -> the term it stands for, in insertion order.
53	    entries: Vec<(String, Term)>,
54	    /// canonical fully-expanded key -> assigned name (dedup).
55	    by_key: HashMap<String, String>,
56	    /// prefix -> next counter value.
57	    counters: HashMap<String, u32>,
58	}
59	
60	impl Abbreviator {
61	    pub fn new() -> Self {
62	        Self::default()
63	    }
64	
65	    /// Register `term` for abbreviation, returning its name. Terms that render
66	    /// identically (fully expanded) share one name.
67	    pub fn add(&mut self, term: Term) -> String {
68	        let key = term.render_full();
69	        if let Some(existing) = self.by_key.get(&key) {
70	            return existing.clone();
71	        }
72	        let prefix = prefix_for_symbol(&term.root_symbol_name());
73	        let n = self.counters.entry(prefix.clone()).or_insert(0);
74	        *n += 1;
75	        let name = format!("{}{}", prefix, n);
76	        self.by_key.insert(key, name.clone());
77	        self.entries.push((name.clone(), term));
78	        name
79	    }
80	
81	    /// The name for an already-registered term, if any (by full rendering).
82	    pub fn name_of(&self, term: &Term) -> Option<&str> {
83	        self.by_key.get(&term.render_full()).map(String::as_str)
84	    }
85	
86	    /// Legend rows `(name, expansion)` in insertion order. Each expansion renders
87	    /// the term one level with any registered *sub*-term replaced by its name
88	    /// (nesting, §5b: `EX1 = 'g'^MU1`). The expansion string is NOT yet
89	    /// HTML-escaped; [`legend_html`] escapes it.
90	    pub fn rows(&self) -> Vec<(String, String)> {
91	        self.entries
92	            .iter()
93	            .map(|(name, term)| (name.clone(), term.render_abbrev(&self.by_key)))
94	            .collect()
95	    }
96	
97	    /// Render the legend as the exact inner HTML of the `plain` node's label
98	    /// (the bytes between `label=<` and `>`). Empty if no entries.
99	    pub fn legend_html(&self) -> String {
100	        legend_html(&self.rows())
101	    }
102	
103	    pub fn is_empty(&self) -> bool {
104	        self.entries.is_empty()
105	    }
106	    pub fn len(&self) -> usize {
107	        self.entries.len()
108	    }
109	}
110	
111	/// HTML-escape a legend expansion: `&`→`&amp;`, `<`→`&lt;`, `>`→`&gt;`. Single
112	/// quotes and `* ^ ~ $ ⊕ ++` are left literal (as observed).
113	pub fn escape_expansion(s: &str) -> String {
114	    let mut out = String::with_capacity(s.len());
115	    for c in s.chars() {
116	        match c {
117	            '&' => out.push_str("&amp;"),
118	            '<' => out.push_str("&lt;"),
119	            '>' => out.push_str("&gt;"),
120	            _ => out.push(c),
121	        }
122	    }
123	    out
124	}
125	
126	/// Render one legend row's `<TR>…</TR>` (expansion is escaped here).
127	fn legend_row(name: &str, expansion: &str) -> String {
128	    format!(
129	        "<TR><TD ALIGN=\"LEFT\" VALIGN=\"TOP\"><FONT COLOR=\"#000000\">{}</FONT></TD> <TD ALIGN=\"LEFT\" VALIGN=\"TOP\">=</TD> <TD ALIGN=\"LEFT\" VALIGN=\"TOP\">{}</TD></TR>",
130	        name,
131	        escape_expansion(expansion),
132	    )
133	}
134	
135	/// The exact inner HTML for the legend `plain` node (between `label=<` and `>`):
136	/// `<TABLE …><TR>row0</TR>\n<65sp><TR>row1</TR>\n…<65sp><TR>rowN</TR></TABLE>`.
137	/// The first row is inline after the table tag; every continuation row is on its
138	/// own line indented by `TABLE_OPEN.len()` (= 65) spaces.
139	pub fn legend_html(rows: &[(String, String)]) -> String {
140	    if rows.is_empty() {
141	        return String::new();
142	    }
143	    let indent = " ".repeat(TABLE_OPEN.len());
144	    let mut s = String::new();
145	    s.push_str(TABLE_OPEN);
146	    for (i, (name, exp)) in rows.iter().enumerate() {
147	        if i > 0 {
148	            s.push('\n');
149	            s.push_str(&indent);
150	        }
151	        s.push_str(&legend_row(name, exp));
152	    }
153	    s.push_str("</TABLE>");
154	    s
155	}
156	
157	/// Minimum fully-expanded rendered length for a sub-term to be abbreviated.
158	/// Corpus-exact: the shortest of 97 538 legend expansions is 10 chars, none is 9;
159	/// live probe: `'12345678'` (10) is abbreviated, `'1234567'` (9) is not.
160	pub const MIN_ABBREV_LEN: usize = 10;
161	/// Minimum occurrence count for a sub-term to be abbreviated. Live probe: a
162	/// 12-char term is abbreviated at 2 occurrences, a 42-char term is NOT at 1.
163	pub const MIN_ABBREV_OCC: usize = 2;
164	
165	/// Select which sub-terms of `roots` to abbreviate (BEHAVIOR.md §5c).
166	///
167	/// **The rule** (each gate confirmed independently by controlled black-box
168	/// probes; both necessary gates are corpus-exact with 0 counterexamples over
169	/// 97 538 abbreviations): a sub-term `t` is abbreviated **iff**
170	///  1. `t.render_len() >= MIN_ABBREV_LEN` (10),
171	///  2. `t` occurs `>= MIN_ABBREV_OCC` (2) times across `roots`, and
172	///  3. `t` is not a tuple/pair.
173	///
174	/// Atoms are eligible (a long constant/variable is abbreviated). Selection is
175	/// bottom-up (shortest first) so nested eligible sub-terms are named before the
176	/// terms that contain them (`LO1='longarg123'` before `H1='h(LO1)'`).
177	///
178	/// `roots` must be the full multiset of constraint-system terms (graph node-fact
179	/// arguments **and** the sequent's terms) — occurrence is a whole-system count,
180	/// not a per-drawn-node count. See BEHAVIOR.md §5c for the one documented
181	/// residual: for DH-exponentiation / AC-operator (`^ * ⊕ ++`) sub-terms tamarin
182	/// counts occurrences over the *normalised* term, which this structural count
183	/// does not model, so those may be over- or under-selected.
184	pub fn select(roots: &[Term]) -> Vec<Term> {
185	    select_with(roots, MIN_ABBREV_LEN, MIN_ABBREV_OCC)
186	}
187	
188	/// [`select`] with explicit thresholds (for probing / tests).
189	pub fn select_with(roots: &[Term], min_len: usize, min_occ: usize) -> Vec<Term> {
190	    let mut counts: HashMap<String, (usize, Term)> = HashMap::new();
191	    for r in roots {
192	        r.for_each_subterm(&mut |t| {
193	            if t.is_tuple() || t.render_len() < min_len {
194	                return;
195	            }
196	            let e = counts.entry(t.render_full()).or_insert((0, t.clone()));
197	            e.0 += 1;
198	        });
199	    }
200	    let mut picked: Vec<Term> = counts
201	        .into_values()
202	        .filter(|(c, _)| *c >= min_occ)
203	        .map(|(_, t)| t)
204	        .collect();
205	    // bottom-up: shortest rendering first so inner names are assigned before outer.
206	    picked.sort_by(|a, b| {
207	        a.render_len().cmp(&b.render_len()).then_with(|| a.render_full().cmp(&b.render_full()))
208	    });
209	    picked
210	}
