70	/// Bulk generalization check (off by default). Set `GRAPHCLEAN_CORPUS` to a
71	/// directory of captured `*.dot` payloads; every one must round-trip byte-exact.
72	#[test]
73	fn roundtrip_corpus_dir() {
74	    let Ok(dir) = std::env::var("GRAPHCLEAN_CORPUS") else {
75	        return;
76	    };
77	    let mut total = 0usize;
78	    let mut ok = 0usize;
79	    let mut fails: Vec<String> = Vec::new();
80	    for entry in std::fs::read_dir(&dir).unwrap() {
81	        let path = entry.unwrap().path();
82	        if path.extension().and_then(|e| e.to_str()) != Some("dot") {
83	            continue;
84	        }
85	        let dot = std::fs::read_to_string(&path).unwrap();
86	        total += 1;
87	        let out = std::panic::catch_unwind(|| to_dot(&parse(&dot)))
88	            .unwrap_or_else(|_| String::from("<PANIC>"));
89	        if out == dot {
90	            ok += 1;
91	        } else if fails.len() < 20 {
92	            fails.push(path.file_name().unwrap().to_string_lossy().into_owned());
93	        }
94	    }
95	    eprintln!("corpus round-trip: {ok}/{total} byte-exact");
96	    for f in &fails {
97	        eprintln!("  MISMATCH: {f}");
98	    }
99	    assert_eq!(ok, total, "{} of {} payloads failed to round-trip", total - ok, total);
100	}
