1	//! Shared test-only ingest: a minimal parser for the exact DOT dialect the
2	//! tamarin web UI emits, reading a captured payload into the crate's [`Graph`]
3	//! model. Used by both the round-trip and allocator corpus tests. Not part of the
4	//! crate's public API — this is observation tooling, not the reimplementation.
5	#![allow(dead_code)]
6	
7	use graph_clean::model::*;
8	
9	/// Merge a plain-node legend that spans several physical lines into one logical
10	/// line, so every statement is a single element.
11	pub fn logical_lines(dot: &str) -> Vec<String> {
12	    let raw: Vec<&str> = dot.split('\n').collect();
13	    let mut out: Vec<String> = Vec::new();
14	    let mut i = 0;
15	    while i < raw.len() {
16	        let line = raw[i];
17	        if line.contains("shape=\"plain\"") && !line.trim_end().ends_with("];") {
18	            let mut buf = String::from(line);
19	            i += 1;
20	            loop {
21	                buf.push('\n');
22	                buf.push_str(raw[i]);
23	                if raw[i].trim_end().ends_with("];") {
24	                    break;
25	                }
26	                i += 1;
27	            }
28	            out.push(buf);
29	            i += 1;
30	        } else {
31	            out.push(line.to_string());
32	            i += 1;
33	        }
34	    }
35	    out
36	}
37	
38	pub fn parse(dot: &str) -> Graph {
39	    let lines = logical_lines(dot);
40	    let header = if lines.iter().any(|l| l == "packmode=\"cluster\";") {
41	        Header::Compact
42	    } else {
43	        Header::Simple
44	    };
45	    let mut idx = lines.iter().position(|l| l == "digraph \"G\" {").unwrap() + 1;
46	    let mut g = Graph::new(header);
47	    g.body = parse_block(&lines, &mut idx);
48	    g
49	}
50	
51	fn parse_block(lines: &[String], idx: &mut usize) -> Vec<Stmt> {
52	    let mut out = Vec::new();
53	    while *idx < lines.len() {
54	        let line = lines[*idx].clone();
55	        let trimmed = line.trim_end();
56	        if trimmed == "}" {
57	            *idx += 1;
58	            return out;
59	        }
60	        if trimmed.is_empty() || is_block_attr(trimmed) {
61	            *idx += 1;
62	            continue;
63	        }
64	        if trimmed.starts_with("subgraph \"cluster_") {
65	            let label = trimmed
66	                .trim_start_matches("subgraph \"cluster_")
67	                .trim_end_matches("\" {")
68	                .to_string();
69	            *idx += 1;
70	            let color = capture_attr(lines, *idx, "color").unwrap();
71	            let body = parse_block(lines, idx);
72	            out.push(Stmt::Cluster(Cluster { label, color, body }));
73	            continue;
74	        }
75	        if trimmed == "{" {
76	            *idx += 1;
77	            let rank = capture_attr(lines, *idx, "rank").unwrap();
78	            let body = parse_block(lines, idx);
79	            out.push(Stmt::RankBlock(RankBlock { rank, body }));
80	            continue;
81	        }
82	        if line.contains(" -> ") {
83	            out.push(Stmt::Edge(parse_edge(&line)));
84	        } else {
85	            out.push(Stmt::Node(parse_node(&line)));
86	        }
87	        *idx += 1;
88	    }
89	    out
90	}
91	
92	fn is_block_attr(l: &str) -> bool {
93	    if l.starts_with("node[") || l.starts_with("edge[") {
94	        return true;
95	    }
96	    if l.contains('[') {
97	        return false;
98	    }
99	    if let Some(eq) = l.find('=') {
100	        let key = &l[..eq];
101	        return key.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit()) && l.ends_with(';');
102	    }
103	    false
104	}
105	
106	fn capture_attr(lines: &[String], from: usize, key: &str) -> Option<String> {
107	    let needle = format!("{}=\"", key);
108	    for l in &lines[from..] {
109	        let t = l.trim();
110	        if t.starts_with(&needle) {
111	            let rest = &t[needle.len()..];
112	            return Some(rest.trim_end_matches("\";").trim_end_matches('"').to_string());
113	        }
114	        if t == "}" {
115	            break;
116	        }
117	    }
118	    None
