121	fn parse_node(line: &str) -> Node {
122	    let l = line.trim_end();
123	    let br = l.find('[').unwrap();
124	    let id = l[..br].to_string();
125	    let attrs = &l[br + 1..l.rfind("];").unwrap()];
126	    if attrs.starts_with("shape=\"record\"") {
127	        let label_start = l.find(",label=\"").unwrap() + ",label=\"".len();
128	        let label_end = l.find("\",fillcolor=\"").unwrap();
129	        let label = &l[label_start..label_end];
130	        let fillcolor = extract(l, "fillcolor=\"");
131	        let fontcolor = extract(l, "fontcolor=\"");
132	        let role = extract(l, "role=\"");
133	        Node::record(
134	            id,
135	            Record { columns: parse_record_label(label), fillcolor, fontcolor, role: Role(role) },
136	        )
137	    } else if attrs.starts_with("shape=\"plain\"") {
138	        let start = l.find("label=<").unwrap() + "label=<".len();
139	        let end = l.rfind(">];").unwrap();
140	        Node::plain(id, &l[start..end])
141	    } else {
142	        let label_start = l.find("label=\"").unwrap() + "label=\"".len();
143	        let label_end = l.find("\",shape=\"").unwrap();
144	        let label = l[label_start..label_end].to_string();
145	        let shape = extract(l, "shape=\"");
146	        let color = if l.contains(",color=\"") { Some(extract(l, ",color=\"")) } else { None };
147	        if shape == "ellipse" {
148	            Node::ellipse(id, Ellipse { label, color })
149	        } else {
150	            Node::shaped(id, Shaped { label, shape, color })
151	        }
152	    }
153	}
154	
155	fn extract(l: &str, key: &str) -> String {
156	    let s = l.find(key).unwrap() + key.len();
157	    let rest = &l[s..];
158	    let e = rest.find('"').unwrap();
159	    rest[..e].to_string()
160	}
