162	fn parse_record_label(s: &str) -> Vec<Vec<Cell>> {
163	    let inner = &s[1..s.len() - 1];
164	    split_top(inner, '|')
165	        .into_iter()
166	        .map(|group| {
167	            let g = &group[1..group.len() - 1];
168	            split_top(g, '|').into_iter().map(|cell| parse_cell(&cell)).collect()
169	        })
170	        .collect()
171	}
172	
173	fn parse_cell(cell: &str) -> Cell {
174	    let gt = find_unescaped(cell, '>').unwrap();
175	    let port = cell[1..gt].to_string();
176	    let text = cell[gt + 2..].to_string();
177	    Cell { port, text }
178	}
179	
180	fn split_top(s: &str, sep: char) -> Vec<String> {
181	    let mut parts = Vec::new();
182	    let mut depth = 0i32;
183	    let mut cur = String::new();
184	    let mut esc = false;
185	    for c in s.chars() {
186	        if esc {
187	            cur.push(c);
188	            esc = false;
189	            continue;
190	        }
191	        match c {
192	            '\\' => {
193	                cur.push(c);
194	                esc = true;
195	            }
196	            '{' => {
197	                depth += 1;
198	                cur.push(c);
199	            }
200	            '}' => {
201	                depth -= 1;
202	                cur.push(c);
203	            }
204	            _ if c == sep && depth == 0 => {
205	                parts.push(std::mem::take(&mut cur));
206	            }
207	            _ => cur.push(c),
208	        }
209	    }
210	    parts.push(cur);
211	    parts
212	}
213	
214	fn find_unescaped(s: &str, target: char) -> Option<usize> {
215	    let mut esc = false;
216	    for (i, c) in s.char_indices() {
217	        if esc {
218	            esc = false;
219	            continue;
220	        }
221	        if c == '\\' {
222	            esc = true;
223	        } else if c == target {
224	            return Some(i);
225	        }
226	    }
227	    None
228	}
229	
230	fn parse_edge(line: &str) -> Edge {
231	    let l = line.trim_end().trim_end_matches(';');
232	    let arrow = l.find(" -> ").unwrap();
233	    let src = parse_endpoint(&l[..arrow]);
234	    let rest = &l[arrow + 4..];
235	    let (dst_str, attrs) = match rest.find('[') {
236	        Some(b) => (&rest[..b], parse_attrs(&rest[b + 1..rest.rfind(']').unwrap()])),
237	        None => (rest, Vec::new()),
238	    };
239	    Edge { src, dst: parse_endpoint(dst_str), attrs }
240	}
241	
242	fn parse_endpoint(s: &str) -> EndPoint {
243	    match s.find(':') {
244	        Some(c) => EndPoint::port(s[..c].to_string(), s[c + 1..].to_string()),
245	        None => EndPoint::node(s.to_string()),
246	    }
247	}
248	
249	fn parse_attrs(s: &str) -> Vec<(String, String)> {
250	    let mut out = Vec::new();
251	    for part in s.split("\",") {
252	        let part = part.trim_end_matches('"');
253	        if let Some(eq) = part.find("=\"") {
254	            out.push((part[..eq].to_string(), part[eq + 2..].to_string()));
255	        }
256	    }
257	    out
258	}
