        .premises(vec![Fact::new("Fr", vec![fresh("s")])])
        .actions(vec![Fact::new(&format!("W{}", p), vec![])])
        .conclusions(vec![Fact::new("Out", vec![Term::tuple(vec![atom, Term::cst("y")])])]);
